"""Regression test for --no-fold-skipped CLI option (issue #9876, PR #12567).

This test FAILS on buggy code (which lacks --no-fold-skipped support) and
PASSES on fixed code (which implements --no-fold-skipped).
"""

from __future__ import annotations

import pytest
from _pytest.pytester import Pytester


class TestNoFoldSkipped:
    def test_no_fold_skipped_option_exists(self, pytester: Pytester) -> None:
        """Test that --no-fold-skipped CLI option is recognized (not an error)."""
        pytester.makepyfile(
            """
            import pytest

            @pytest.mark.skip("Some reason")
            def test_something():
                pass
            """
        )
        result = pytester.runpytest("--no-fold-skipped", "-rs")
        # On buggy code, --no-fold-skipped is unrecognized, causing exit code 4 (usage error)
        # On fixed code, it should be recognized and run normally (exit code 0 or 1)
        assert result.ret != 4, (
            "--no-fold-skipped option was not recognized (usage error). "
            "The option may not be implemented yet."
        )

    def test_no_fold_skipped_shows_node_ids(self, pytester: Pytester) -> None:
        """Test that --no-fold-skipped shows individual test node IDs in summary."""
        pytester.makepyfile(
            """
            import pytest

            @pytest.mark.parametrize("param", [True, False])
            @pytest.mark.skip("Some reason")
            def test_skipped(param):
                pass
            """
        )
        result = pytester.runpytest("-rs", "--no-fold-skipped")

        # On fixed code: each skipped test should appear with its node ID
        result.stdout.fnmatch_lines([
            "SKIPPED test_no_fold_skipped_shows_node_ids.py::test_skipped[True] - Skipped: Some reason",
            "SKIPPED test_no_fold_skipped_shows_node_ids.py::test_skipped[False] - Skipped: Some reason",
        ])

    def test_no_fold_skipped_does_not_fold(self, pytester: Pytester) -> None:
        """Test that --no-fold-skipped does NOT produce folded SKIPPED [N] lines."""
        pytester.makepyfile(
            """
            import pytest

            @pytest.mark.parametrize("param", [True, False])
            @pytest.mark.skip("Some reason")
            def test_skipped(param):
                pass
            """
        )
        result = pytester.runpytest("-rs", "--no-fold-skipped")

        # On fixed code: the folded format SKIPPED [2] ... should NOT appear
        stdout = result.stdout.str()
        assert "SKIPPED [2]" not in stdout, (
            "With --no-fold-skipped, skipped tests should not be folded. "
            "Found 'SKIPPED [2]' in output which indicates folding is still active."
        )

    def test_no_fold_skipped_each_test_separate_line(self, pytester: Pytester) -> None:
        """Test that with --no-fold-skipped each skipped test appears on its own line."""
        pytester.makepyfile(
            """
            import pytest

            @pytest.mark.parametrize("param", ["a", "b", "c"])
            @pytest.mark.skip("reason for skipping")
            def test_multi(param):
                pass
            """
        )
        result = pytester.runpytest("-rs", "--no-fold-skipped")

        stdout_lines = result.stdout.lines
        skipped_lines = [l for l in stdout_lines if "SKIPPED" in l and "test_multi" in l]

        # There should be 3 individual lines, one per parametrized variant
        assert len(skipped_lines) == 3, (
            f"Expected 3 individual SKIPPED lines with node IDs, got {len(skipped_lines)}. "
            f"Lines found: {skipped_lines}"
        )

    def test_default_behavior_still_folds(self, pytester: Pytester) -> None:
        """Test that without --no-fold-skipped, the default behavior still folds."""
        pytester.makepyfile(
            """
            import pytest

            @pytest.mark.parametrize("param", [True, False])
            @pytest.mark.skip("Some reason")
            def test_skipped(param):
                pass
            """
        )
        result = pytester.runpytest("-rs")

        # Default behavior: folded output with count
        result.stdout.fnmatch_lines([
            "SKIPPED [2] test_default_behavior_still_folds.py:3: Some reason"
        ])

    def test_no_fold_skipped_with_different_reasons(self, pytester: Pytester) -> None:
        """Test that --no-fold-skipped shows each test separately even with different reasons."""
        pytester.makepyfile(
            """
            import pytest

            @pytest.mark.skip("reason one")
            def test_first():
                pass

            @pytest.mark.skip("reason two")
            def test_second():
                pass
            """
        )
        result = pytester.runpytest("-rs", "--no-fold-skipped")

        result.stdout.fnmatch_lines([
            "SKIPPED test_no_fold_skipped_with_different_reasons.py::test_first - Skipped: reason one",
            "SKIPPED test_no_fold_skipped_with_different_reasons.py::test_second - Skipped: reason two",
        ])

    def test_no_fold_skipped_option_is_false_action(self, pytester: Pytester) -> None:
        """Test that --no-fold-skipped sets fold_skipped to False (store_false action)."""
        pytester.makepyfile(
            """
            import pytest

            @pytest.mark.skip("test reason")
            def test_example():
                pass
            """
        )
        # Run with --no-fold-skipped
        result_unfolded = pytester.runpytest("-rs", "--no-fold-skipped")

        # Should NOT contain folded format
        assert "SKIPPED [1]" not in result_unfolded.stdout.str(), (
            "--no-fold-skipped should prevent the folded 'SKIPPED [N]' format"
        )

        # Should contain the node id format
        assert "test_example" in result_unfolded.stdout.str(), (
            "--no-fold-skipped should show the test node ID in summary"
        )

